  "2. Lavado premium\n" +
  "Nuestra opción más completa. Recomendado si buscas una limpieza más detallada por dentro y por fuera, con una terminación más cuidada.\n\n" +
  "3. Encerado full\n" +
  "Servicio enfocado en proteger la pintura y realzar el brillo del vehículo. Ideal para darle una mejor terminación y mayor protección exterior.\n\n" +
  "Para darte el valor exacto, dime qué tipo de vehículo tienes y en qué comuna sería el servicio.";

return [{
  ...data,

  message_to_send: message,

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...(data.state_update || {}),

    stage: "service_discovery",
    intent_last: "service_menu_request",
    next_goal: "collect_vehicle_and_district",
    last_bot_action: "send_service_menu",

    service_interest: ctx.service_interest || state.service_interest || null,
    vehicle_type: vehicleType || null,
    district: district || null,

    missing_fields: missingFields
  },

  execution_context: {
    ...ctx,
    action: "send_service_menu"
  },

  execution_result: {
    success: true,
    action: "send_service_menu",
    message_sent: false,
    state_updated: true,
    db_records_created: ["messages", "lead_state"],
    notes: ["service_menu_sent"]
  },

  notes: ["service_menu_sent"]
}];

